const emailBody = $json.text || $json.response || $json.output || "";

return [{
  json: {
    ...$input.first().json,
    email_body: emailBody,
    text: "Demande comprise. Email préparé et envoyé à l'adresse de test " +
      ($input.first().json.email_to || "test@demo.local") +
      ". Objet : " +
      (($input.first().json.email_subject) || "Nouvelle demande client")
  }
}];

const raw = $json.text || $json.response || $json.output || '';
let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  parsed = {
    request_type: 'demande_generique',
    summary: 'Réponse IA non parseable.',
    score_confiance: 0,
    needs_clarification: true,
    missing_fields: ['analyse_json'],
    action_recommandee: 'clarifier',
    email_to: null,
    proposed_email_subject: 'Demande à clarifier',
    extracted_data: {},
    raw_llm_output: raw
  };
}
return [{ json: { ...$input.first().json, ...parsed } }];
